try {




import com.liferay.jenkins.results.parser.JenkinsResultsParserUtil;

import org.apache.commons.lang.StringUtils;

import org.json.JSONArray;
import org.json.JSONObject;

JSONArray repositoryInvitationsArray = JenkinsResultsParserUtil.toJSONArray("https://api.github.com/user/repository_invitations");

for (int i = 0; i < repositoryInvitationsArray.length(); i++) {
	Object object = repositoryInvitationsArray.get(i);

	if (object.equals(JSONObject.NULL)) {
		continue;
	}

	JSONObject repositoryInvitationJSONObject = repositoryInvitationsArray.get(i);

	JSONObject repositoryJSONObject = repositoryInvitationJSONObject.getJSONObject("repository");

	Integer id = repositoryInvitationJSONObject.getInt("id");

	StringBuilder sb = new StringBuilder();

	sb.append("curl ");
	sb.append("-X PATCH ");
	sb.append("-H 'Authorization: token ");
	sb.append(project.getProperty("env.GITHUB_AUTHORIZATION_KEY"));
	sb.append("' ");
	sb.append("https://api.github.com/user/repository_invitations/" + id);

	JenkinsResultsParserUtil.executeBashCommands(new String[] {sb.toString()});

	System.out.println("Approved collaborator for " + repositoryJSONObject.getString("full_name"));
}





}
catch (Exception e) {
	e.printStackTrace();
}


try {




import com.liferay.jenkins.results.parser.JenkinsResultsParserUtil;

import org.apache.commons.lang.StringUtils;

import org.json.JSONArray;
import org.json.JSONObject;

public String getBranchName(JSONObject pullJSONObject) {
	JSONObject baseJSONObject = pullJSONObject.getJSONObject("base");

	return baseJSONObject.getString("ref");
}

String repositories = project.getProperty("repositories");
String usernames = project.getProperty("usernames");

for (String username : usernames.split(",")) {
	for (String repository : repositories.split(",")) {
		JSONArray pullsJSONArray = JenkinsResultsParserUtil.toJSONArray("https://api.github.com/repos/" + username + "/" + repository + "/pulls");

		for (int i = 0; i < pullsJSONArray.length(); i++) {
			Object object = pullsJSONArray.get(i);

			if (object.equals(JSONObject.NULL)) {
				continue;
			}

			JSONObject pullJSONObject = pullsJSONArray.get(i);

			JSONArray labelsJSONArray = pullJSONObject.getJSONArray("labels");

			boolean found = false;

			for (int j = 0; j < labelsJSONArray.length(); j++) {
				if (found) {
					break;
				}

				Object object = labelsJSONArray.get(j);

				if (object.equals(JSONObject.NULL)) {
					continue;
				}

				JSONObject labelJSONObject = labelsJSONArray.get(j);

				String labelName = labelJSONObject.getString("name");

				if (labelName.contains("ci:test:sf")) {
					found = true;

					break;
				}
			}

			String branchName = getBranchName(pullJSONObject);

			if (!found && !branchName.contains("-private")) {
				StringBuilder sb = new StringBuilder();

				sb.append("http://test-1-1/job/test-portal-source-format/buildWithParameters?token=raen3Aib&");
				sb.append("PULL_REQUEST_URL=");
				sb.append(pullJSONObject.getString("html_url"));

				String triggerBuilds = project.getProperty("trigger.builds");

				System.out.println("Running: " + sb.toString());

				if (triggerBuilds != null && triggerBuilds.equals("true")) {
					JenkinsResultsParserUtil.toString(sb.toString());

					System.out.println("TRIGGERED!");
				}
			}
		}
	}
}


}
catch (Exception e) {
	e.printStackTrace();
}


