try {




import com.liferay.jenkins.results.parser.JobFactory;
import com.liferay.jenkins.results.parser.PortalRepositoryJob;
import com.liferay.jenkins.results.parser.RepositoryJob;
import com.liferay.jenkins.results.parser.test.clazz.group.AxisTestClassGroup;
import com.liferay.jenkins.results.parser.test.clazz.group.BaseTestClassGroup.BaseTestClass;
import com.liferay.jenkins.results.parser.test.clazz.group.BaseTestClassGroup.BaseTestMethod;
import com.liferay.jenkins.results.parser.test.clazz.group.BatchTestClassGroup;
import com.liferay.jenkins.results.parser.test.clazz.group.FunctionalBatchTestClassGroup;
import com.liferay.jenkins.results.parser.test.clazz.group.TestClassGroupFactory;

import org.apache.commons.lang.StringUtils;

RepositoryJob repositoryJob = (RepositoryJob)JobFactory.newJob(project.getProperty("env.TOP_LEVEL_JOB_NAME"), project.getProperty("env.CI_TEST_SUITE"));

List batchNames = new ArrayList();

String branchName = repositoryJob.getBranchName();

StringBuilder sb = new StringBuilder();

if (repositoryJob instanceof PortalRepositoryJob) {
	PortalRepositoryJob portalRepositoryJob = (PortalRepositoryJob)repositoryJob;

	for (String batchName : portalRepositoryJob.getBatchNames()) {
		if (batchName.contains("plugins-gulp-")) {
			continue;
		}

		BatchTestClassGroup batchTestClassGroup = TestClassGroupFactory.newBatchTestClassGroup(batchName, portalRepositoryJob);

		int axisCount = batchTestClassGroup.getAxisCount();

		/*System.out.println();
		System.out.println("##");
		System.out.println("## " + batchName);
		System.out.println("## " + batchTestClassGroup);
		System.out.println("## " + axisCount);
		System.out.println("##");
		System.out.println();*/

		String propertyName = null;
		String propertyValue = null;

		if (batchTestClassGroup instanceof FunctionalBatchTestClassGroup) {
			FunctionalBatchTestClassGroup functionalBatchTestClassGroup = (FunctionalBatchTestClassGroup)batchTestClassGroup;

			String relevantTestBatchRunPropertyQuery = functionalBatchTestClassGroup.getRelevantTestBatchRunPropertyQuery();

			if (relevantTestBatchRunPropertyQuery != null) {
				batchNames.add(batchName);

				propertyName = "test.batch.run.property.query[" + batchName + "]";
				propertyValue = relevantTestBatchRunPropertyQuery;
			}
		}
		else if (axisCount > 0) {
			batchNames.add(batchName);

			propertyName = "test.batch.size[" + batchName + "]";
			propertyValue = Integer.toString(axisCount);

			for (int i = 0; i < axisCount; i++) {
				AxisTestClassGroup axisTestClassGroups = batchTestClassGroup.getAxisTestClassGroup(i);

				//System.out.println(axisTestClassGroups);

				for (BaseTestClass baseTestClass : axisTestClassGroups.getTestClasses()) {
					// System.out.println("\t" + baseTestClass.getTestMethods().size() + " " + baseTestClass.getFile());

					/*for (BaseTestMethod baseTestMethod : baseTestClass.getTestMethods()) {
						System.out.println("\t\t" + baseTestMethod.getName());
					}*/
				}
			}

			//System.out.println();
		}

		if (propertyName != null) {
			project.setProperty(propertyName, propertyValue);

			sb.append(propertyName);
			sb.append("=");
			sb.append(propertyValue);
			sb.append("\n");
		}
	}
}
else {
	batchNames.addAll(repositoryJob.getBatchNames());
}

project.setProperty("portal.branch.name", branchName);
project.setProperty("test.batch.names", StringUtils.join(batchNames, ","));
project.setProperty("test.dist.types", StringUtils.join(repositoryJob.getDistTypes(), " "));
project.setProperty("test.properties.content", sb.toString());





}
catch (Throwable t) {
	t.printStackTrace();
}


try {



